INSERT INTO `oc_product_description` VALUES
(50,1,'Насос для перекачки масла ручной GEKO TI G01019','<p><b>\n	Насос для перекачки масла ручной GEKO TI G01019</b></p><p><b>Ручной поршневой насос</b> предназначен для перекачивания масла.</p><p><br></p><p>Насос характеризуется высоким КПД, прочной конструкцией и простотой использования.</p><p><br></p><p><b>Благодаря использованию телескопической всасывающей трубы мы можем подогнать длину насоса к имеющейся у нас бочке.</b></p><p><b>Особенности продукта:</b></p><p>Высокая производительность, около 25 л/мин</p><p>Емкость 0,35 л</p><p>Для бочек 50, 100, 200 литров</p><p>Телескопическая всасывающая труба</p><p>Два размера резьбы для крепления к стволу</p>','','Насос для перекачки масла ручной GEKO TI G01019','',''),
(51,1,'Динамометрический ключ 3-8\"DR 19-110HM. 365мм. 820гр.','<p><br> <strong>Динамометрический ключ 3-8\"DR 19-110HM. 365мм. 820гр.</strong> – лучшее решение для Вас и Вашего автомобиля. </p><br><p><br> Наборы инструментов для авто Автоинструмент Инструмент <strong>DК-323-2 (24)</strong> от известного производителя <b>ALLOID</b> – заказ будет доставлен по Киеву и (или) Украине, если Вы оформите его через корзину или позвоните по телефону. Наши менеджеры, при необходимости, предоставят квалифицированную консультацию. </p><br><p><br> Вы можете заказать другие аксессуары из категории <strong>Наборы инструментов для авто Автоинструмент Инструмент </strong> на нашем сайте shopauto.com.ua</p>','','Динамометрический ключ 3-8\"DR 19-110HM. 365мм. 820гр.','',''),
(52,1,'Динамометрический ключ 1-4\"DR 5-25HM, 275мм, 580гр.','<p><br> <strong>Динамометрический ключ 1-4\"DR 5-25HM, 275мм, 580гр.</strong> – лучшее решение для Вас и Вашего автомобиля. </p><br><p><br> Наборы инструментов для авто Автоинструмент Инструмент <strong>DК- 223-1 (12)</strong> от известного производителя <b>ALLOID</b> – заказ будет доставлен по Киеву и (или) Украине, если Вы оформите его через корзину или позвоните по телефону. Наши менеджеры, при необходимости, предоставят квалифицированную консультацию. </p><br><p><br> Вы можете заказать другие аксессуары из категории <strong>Наборы инструментов для авто Автоинструмент Инструмент </strong> на нашем сайте shopauto.com.ua</p>','','Динамометрический ключ 1-4\"DR 5-25HM, 275мм, 580гр.','',''),
(53,1,'Ключ баллонный \"крест\"17х19х21 мм. 1-2\"','<p><br> <strong>Alloid. Ключ балонный \"крест\" 17х19х21 мм. 1/2\"</strong> – лучшее решение для Вас и Вашего автомобиля. </p><br><p><br> Ключи гаечные комбинированные Ключи гаечные Ключи Автоинструмент Инструмент <strong>КБ-201721 (20)</strong> от известного производителя <b>ALLOID</b> – заказ будет доставлен по Киеву и (или) Украине, если Вы оформите его через корзину или позвоните по телефону. Наши менеджеры, при необходимости, предоставят квалифицированную консультацию. </p><br><p><br> Вы можете заказать другие аксессуары из категории <strong>Ключи гаечные комбинированные Ключи гаечные Ключи Автоинструмент Инструмент</strong> на нашем сайте shopauto.com.ua</p>','','Ключ баллонный \"крест\"17х19х21 мм. 1-2\"','',''),
(54,1,'Ключ баллонный 17х19мм/21х23мм. 1-2\"','<p><br> <strong>Alloid. Ключ балонный 17х19мм/21х23мм. 1/2\"</strong> – лучшее решение для Вас и Вашего автомобиля. </p><br><p><br> Ключи гаечные комбинированные Ключи гаечные Ключи Автоинструмент Инструмент <strong>КБ-1723 (10)</strong> от известного производителя <b>ALLOID</b> – заказ будет доставлен по Киеву и (или) Украине, если Вы оформите его через корзину или позвоните по телефону. Наши менеджеры, при необходимости, предоставят квалифицированную консультацию. </p><br><p><br> Вы можете заказать другие аксессуары из категории <strong>Ключи гаечные комбинированные Ключи гаечные Ключи Автоинструмент Инструмент</strong> на нашем сайте shopauto.com.ua</p>','','Ключ баллонный 17х19мм/21х23мм. 1-2\"','',''),
